import React from "react";
import { Link } from "react-router-dom";
import "./News.css";

const newsPosts = [
  {
    id: 1,
    title: "Post 1 Title",
    description: "This is a short description for the first news post.",
    image: "/images/news1.jpg",
  },
  {
    id: 2,
    title: "Post 2 Title",
    description: "This is a short description for the second news post.",
    image: "/images/news2.jpg",
  },
  {
    id: 3,
    title: "Post 3 Title",
    description: "This is a short description for the third news post.",
    image: "/images/news3.jpg",
  },
];

const News = () => {
  return (
    <div className="news-section">
      <h2 className="section-title">News & Articles</h2>
      <div className="news-posts">
        {newsPosts.map((post) => (
          <div key={post.id} className="news-card">
            <img src={post.image} alt={post.title} className="news-image" />
            <h3>{post.title}</h3>
            <p>{post.description}</p>
            <Link to={`/news/${post.id}`} className="read-more" target="_blank">Read More</Link>
          </div>
        ))}
      </div>
      {/* The Show More button now opens in a new tab */}
      <a
        href="/all-news"
        target="_blank"
        className="show-more-btn"
      >
        Show More
      </a>
    </div>
  );
};

export default News;
